package com.enterprise.spark.gpu.core import com.enterprise.spark.gpu.core.pipeline.MachineLearningPipelineExecutor
import com.enterprise.spark.gpu.benchmarking.PerformanceBenchmarkService
import com.enterprise.spark.gpu.reporting.ReportGenerationService
import com.typesafe.scalalogging.LazyLogging
import java.time.LocalDateTime
import java.time.format.DateTimeFormatter /** * Single-command execution system for GPU-accelerated Spark pipeline. * * This application provides a unified entry point that executes the complete workflow: * 1. Data generation with realistic synthetic datasets * 2. Machine learning pipeline with GPU-accelerated training * 3. Performance benchmarking (CPU vs GPU comparison) * 4. Professional report generation with visualizations * 5. Comprehensive validation and error handling * * The system is designed to provide immediate, compelling evidence of GPU * acceleration benefits through a single command execution. * * @author Spark GPU Team */
object GpuPipelineApplication extends LazyLogging { /** * Main application entry point for single-command execution. * * Usage: * sbt "run" # Execute complete workflow * sbt "run --quick" # Execute with smaller datasets for quick demo * sbt "run --benchmark-only" # Execute only benchmarking * sbt "run --no-gpu" # Force CPU-only execution * sbt "run --help" # Show usage information */ def main(args: Array[String]): Unit = { val startTime = System.currentTimeMillis() logger.info("=" * 80) logger.info("GPU-ACCELERATED SPARK PIPELINE") logger.info("Single-Command Execution System") logger.info(s"Started at: ${LocalDateTime.now().format(DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss"))}") logger.info("=" * 80) try { val config = parseCommandLineArguments(args) if (config.showHelp) { printUsageInformation() return } validateSystemRequirements() val executionResults = executeCompleteWorkflow(config) val totalExecutionTime = System.currentTimeMillis() - startTime displayExecutionSummary(executionResults, totalExecutionTime) logger.info("=" * 80) logger.info("EXECUTION COMPLETED SUCCESSFULLY") logger.info(s"Total time: ${totalExecutionTime / 1000.0} seconds") logger.info(s"Reports available in: ${executionResults.reportSummary.outputDirectory}") logger.info("=" * 80) } catch { case e: Exception => logger.error("=" * 80) logger.error("EXECUTION FAILED") logger.error(s"Error: ${e.getMessage}") logger.error("=" * 80) logger.error("Full error details:", e) System.exit(1) } } /** * Configuration for pipeline execution. */ case class ExecutionConfig( quickMode: Boolean = false, benchmarkOnly: Boolean = false, forceNonGpu: Boolean = false, showHelp: Boolean = false, outputDirectory: String = "reports" ) /** * Results from complete workflow execution. */ case class WorkflowExecutionResults( pipelineSummary: com.enterprise.spark.gpu.core.pipeline.PipelineExecutionSummary, benchmarkResults: Option[com.enterprise.spark.gpu.benchmarking.BenchmarkResults], reportSummary: com.enterprise.spark.gpu.reporting.ReportGenerationSummary ) /** * Parses command line arguments into execution configuration. */ private def parseCommandLineArguments(args: Array[String]): ExecutionConfig = { var config = ExecutionConfig() args.foreach { case "--quick" => config = config.copy(quickMode = true) case "--benchmark-only" => config = config.copy(benchmarkOnly = true) case "--no-gpu" => config = config.copy(forceNonGpu = true) case "--help" => config = config.copy(showHelp = true) case arg if arg.startsWith("--output=") => config = config.copy(outputDirectory = arg.substring("--output=".length)) case arg => logger.warn(s"Unknown argument: $arg") } config } /** * Validates system requirements before execution. */ private def validateSystemRequirements(): Unit = { logger.info("Validating system requirements...") // Check Java version val javaVersion = System.getProperty("java.version") logger.info(s"Java version: $javaVersion") // Check available memory val runtime = Runtime.getRuntime val maxMemory = runtime.maxMemory() / (1024 * 1024) // MB val totalMemory = runtime.totalMemory() / (1024 * 1024) // MB val freeMemory = runtime.freeMemory() / (1024 * 1024) // MB logger.info(s"JVM Memory - Max: ${maxMemory}MB, Total: ${totalMemory}MB, Free: ${freeMemory}MB") if (maxMemory < 2048) { logger.warn("Low memory detected. Consider increasing JVM heap size with -Xmx4g or higher") } // Check available processors val processors = runtime.availableProcessors() logger.info(s"Available processors: $processors") logger.info("System requirements validation completed") } /** * Executes the complete workflow with all components. */ private def executeCompleteWorkflow(config: ExecutionConfig): WorkflowExecutionResults = { logger.info("Starting complete workflow execution...") // Phase 1: Execute ML Pipeline (unless benchmark-only mode) val pipelineSummary = if (!config.benchmarkOnly) { logger.info("PHASE 1: Executing Machine Learning Pipeline") logger.info("-" * 50) val pipelineExecutor = new MachineLearningPipelineExecutor() val summary = pipelineExecutor.executeComplete() logger.info(s"Pipeline completed in ${summary.totalExecutionTimeMs}ms") logger.info(s"Processed ${summary.dataGenerationSummary.totalRecords:,} records") logger.info(s"GPU acceleration: ${if (summary.gpuAccelerationEnabled) "ENABLED" else "DISABLED"}") Some(summary) } else { logger.info("Skipping ML Pipeline (benchmark-only mode)") None } // Phase 2: Execute Performance Benchmarks logger.info("PHASE 2: Executing Performance Benchmarks") logger.info("-" * 50) val benchmarkService = new PerformanceBenchmarkService() val benchmarkConfig = createBenchmarkConfig(config) val benchmarkResults = benchmarkService.executeComprehensiveBenchmarks(benchmarkConfig) logger.info(s"Benchmarks completed in ${benchmarkResults.totalExecutionTimeMs}ms") logger.info(s"GPU available: ${benchmarkResults.gpuAvailable}") logger.info(s"Executed ${benchmarkResults.benchmarkResults.length} benchmark operations") // Phase 3: Generate Comprehensive Reports logger.info("PHASE 3: Generating Comprehensive Reports") logger.info("-" * 50) val reportService = new ReportGenerationService() val reportConfig = createReportConfig(config) // Use pipeline summary if available, otherwise create a minimal summary for benchmark-only mode val summaryForReporting = pipelineSummary.getOrElse(createMinimalPipelineSummary()) val reportSummary = reportService.generateComprehensiveReports( summaryForReporting, Some(benchmarkResults), reportConfig ) logger.info(s"Reports generated in ${reportSummary.generationTimeMs}ms") logger.info(s"Generated ${reportSummary.generatedFiles.length} report files") logger.info(s"Main report: ${reportSummary.htmlReportPath}") WorkflowExecutionResults( pipelineSummary = summaryForReporting, benchmarkResults = Some(benchmarkResults), reportSummary = reportSummary ) } /** * Creates benchmark configuration based on execution settings. */ private def createBenchmarkConfig(config: ExecutionConfig): PerformanceBenchmarkService.BenchmarkConfig = { if (config.quickMode) { PerformanceBenchmarkService.BenchmarkConfig( iterations = 2, warmupIterations = 1, datasetSizes = Seq(50000, 100000), enableGpuComparison = !config.forceNonGpu, outputDirectory = s"${config.outputDirectory}/benchmarks" ) } else { PerformanceBenchmarkService.BenchmarkConfig( iterations = 3, warmupIterations = 1, datasetSizes = Seq(100000, 500000, 1000000), enableGpuComparison = !config.forceNonGpu, outputDirectory = s"${config.outputDirectory}/benchmarks" ) } } /** * Creates report configuration based on execution settings. */ private def createReportConfig(config: ExecutionConfig): ReportGenerationService.ReportConfig = { ReportGenerationService.ReportConfig( outputDirectory = config.outputDirectory, generateCharts = true, includeExecutiveSummary = true, includeTechnicalDetails = true, chartWidth = 800, chartHeight = 600 ) } /** * Creates a minimal pipeline summary for benchmark-only mode. */ private def createMinimalPipelineSummary(): com.enterprise.spark.gpu.core.pipeline.PipelineExecutionSummary = { import com.enterprise.spark.gpu.core.pipeline._ import com.enterprise.spark.gpu.core.data.{DataGenerationSummary, DataValidationResults} // Create minimal data generation summary val dataGenSummary = DataGenerationSummary( taxiRecords = 0, housingRecords = 0, taxiFilePath = "", housingFilePath = "", generationTimeMs = 0L, validationResults = DataValidationResults(valid = true, "Benchmark-only mode") ) // Create minimal taxi analysis results val taxiResults = TaxiAnalysisResults( totalTrips = 0L, analysisTimeMs = 0L, averageFare = 0.0, peakHours = Seq.empty ) // Create minimal model metrics val dummyModel = null.asInstanceOf[org.apache.spark.ml.PipelineModel] val modelResults = ModelTrainingResults( randomForestMetrics = ModelMetrics("RandomForest", 0.0, 0.0, 0.0, 0L), linearRegressionMetrics = ModelMetrics("LinearRegression", 0.0, 0.0, 0.0, 0L), rfModel = dummyModel, lrModel = dummyModel ) PipelineExecutionSummary( dataGenerationSummary = dataGenSummary, taxiAnalysisResults = taxiResults, modelTrainingResults = modelResults, totalExecutionTimeMs = 0L, gpuAccelerationEnabled = false ) } /** * Displays comprehensive execution summary. */ private def displayExecutionSummary(results: WorkflowExecutionResults, totalExecutionTime: Long): Unit = { logger.info("") logger.info("EXECUTION SUMMARY") logger.info("=" * 50) // Overall metrics logger.info(s"Total Execution Time: ${totalExecutionTime / 1000.0} seconds") logger.info(s"GPU Acceleration: ${if (results.pipelineSummary.gpuAccelerationEnabled) "ENABLED" else "DISABLED"}") // Pipeline metrics (if executed) if (results.pipelineSummary.totalExecutionTimeMs > 0) { logger.info("") logger.info("ML Pipeline Results:") logger.info(s" Records Processed: ${results.pipelineSummary.dataGenerationSummary.totalRecords:,}") logger.info(s" Pipeline Time: ${results.pipelineSummary.totalExecutionTimeMs}ms") val rfMetrics = results.pipelineSummary.modelTrainingResults.randomForestMetrics val lrMetrics = results.pipelineSummary.modelTrainingResults.linearRegressionMetrics logger.info(s" Random Forest R²: ${rfMetrics.r2.formatted("%.4f")}") logger.info(s" Linear Regression R²: ${lrMetrics.r2.formatted("%.4f")}") } // Benchmark results results.benchmarkResults.foreach { benchmarks => logger.info("") logger.info("Performance Benchmark Results:") logger.info(s" Benchmark Time: ${benchmarks.totalExecutionTimeMs}ms") logger.info(s" Operations Tested: ${benchmarks.benchmarkResults.length}") // Calculate average speedup if GPU results available val speedups = benchmarks.benchmarkResults .groupBy(_.operationType) .map { case (operationType, results) => val cpuResults = results.filter(_.executionMode == "CPU") val gpuResults = results.filter(_.executionMode == "GPU") if (cpuResults.nonEmpty && gpuResults.nonEmpty) { val avgCpuTime = cpuResults.map(_.averageTimeMs).sum / cpuResults.length val avgGpuTime = gpuResults.map(_.averageTimeMs).sum / gpuResults.length Some(avgCpuTime.toDouble / avgGpuTime) } else None } .flatten if (speedups.nonEmpty) { val avgSpeedup = speedups.sum / speedups.size logger.info(s" Average GPU Speedup: ${avgSpeedup.formatted("%.2f")}x") } } // Report generation results logger.info("") logger.info("Report Generation Results:") logger.info(s" Files Generated: ${results.reportSummary.generatedFiles.length}") logger.info(s" Main Report: ${results.reportSummary.htmlReportPath}") logger.info(s" Output Directory: ${results.reportSummary.outputDirectory}") logger.info("") logger.info("NEXT STEPS:") logger.info(s"1. Open the HTML report: ${results.reportSummary.htmlReportPath}") logger.info(s"2. Review performance charts in: ${results.reportSummary.outputDirectory}") logger.info("3. Share results with stakeholders using the executive summary") logger.info("4. Consider scaling to larger datasets for production evaluation") } /** * Prints comprehensive usage information. */ private def printUsageInformation(): Unit = { println() println("GPU-Accelerated Spark Pipeline") println("Single-Command Execution System") println("=" * 60) println() println("USAGE:") println(" sbt \"run\" # Execute complete workflow") println(" sbt \"run --quick\" # Quick demo with smaller datasets") println(" sbt \"run --benchmark-only\" # Execute only performance benchmarks") println(" sbt \"run --no-gpu\" # Force CPU-only execution") println(" sbt \"run --output=DIR\" # Specify output directory") println(" sbt \"run --help\" # Show this help information") println() println("WORKFLOW PHASES:") println(" 1. Machine Learning Pipeline") println(" - Generate synthetic datasets (taxi trips, housing data)") println(" - Execute ETL operations and data analysis") println(" - Train ML models (Random Forest, Linear Regression)") println(" - Evaluate model performance and save results") println() println(" 2. Performance Benchmarking") println(" - Compare CPU vs GPU execution times") println(" - Test ETL operations, ML training, aggregations") println(" - Measure throughput and resource utilization") println(" - Generate performance metrics and speedup analysis") println() println(" 3. Report Generation") println(" - Create professional HTML reports with charts") println(" - Generate executive summary for stakeholders") println(" - Export CSV data for further analysis") println(" - Produce performance comparison visualizations") println() println("OUTPUT:") println(" - HTML Report: Comprehensive performance analysis") println(" - CSV Files: Raw data for custom analysis") println(" - PNG Charts: Performance comparison visualizations") println(" - Executive Summary: Business-focused results") println() println("REQUIREMENTS:") println(" - Java 11 or later") println(" - Apache Spark 3.5.1") println(" - 4GB+ RAM recommended") println(" - NVIDIA GPU + CUDA (optional, for GPU acceleration)") println() println("For more information, see README.md and documentation.") println() }
}